def _JSONdefault(o):
    """Turn an object into JSON.  
    Dates and instances of classes derived from CryptoTyped get special handling"""
    if isinstance(o, datetime.datetime):
        return False
    if isinstance(o, rsa.RSAPublicKey):
        return o.public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        ).decode('utf-8')
    if isinstance(o, rsa.RSAPrivateKey):
        return o.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.PKCS8,
            encryption_algorithm=serialization.NoEncryption()
        ).decode('utf-8')
    if isinstance(o, bytes):
        return o.decode('utf-8')
    return str(o)

def hash(self):
    pk = self.PublicKey        
    source = [pk.public_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PublicFormat.SubjectPublicKeyInfo
    ).decode('utf-8'), 
              self.Name,
              self.json_["NotAfter"], 
              self.json_["NotBefore"],
              self.Serial]
    source = [s.encode('utf8') for s in source]
    source += [self.PublicKey.public_bytes(
        encoding=serialization.Encoding.X962,
        format=serialization.PublicFormat.SubjectPublicKeyInfo
    ).decode('utf-8')]
    if "CriticalExtensions" in self.json_:
        source += [e.cannon() for e in self.CriticalExtensions]
    if "Extensions" in self.json_:
        source += [e.cannon() for e in self.Extensions]

    source = "\x00".join(source)
    return hashlib.sha256(source.encode('utf-8')).hexdigest()

def readable_hash(self):
    dig = hashlib.sha256(self.Hash.encode('utf-8')).hexdigest()
    f = []
    for i in range(len(dig) / 64):
        f.append(dig[i*64:(i+1)*64])
    return ":".join(f)

@Props(Algorithm=["RSA-PKCS1-1.5"], Exponent=LongCodec, Modulus=LongCodec)
@TypeName("publickey")
class PublicKey(CryptoTyped):
    def __init__(self, key=None, json=None):
        super(PublicKey, self).__init__(json)
        if key:
            self.key = key
            self.Exponent = key.e
            self.Modulus = key.n
            self.Algorithm = "RSA-PKCS1-1.5"
        else:
            n = self.Modulus
            e = self.Exponent
            self.key = rsa.generate_private_key(
                public_exponent=e,
                key_size=n,
                backend=default_backend()
            )

    def verify(self, signed_data, signature, signature_algorithm="RSA-PKCS1-1.5", digest_algorithm="SHA256"):
        dig = hashlib.sha256(signed_data.encode('utf-8')).hexdigest()
        if signature_algorithm != "RSA-PKCS1-1.5":
            raise CryptoException("Unknown signature algorithm")
        try:
            self.key.verify(
                asym_padding.PSS(
                    mgf=asym_padding.MGF1(hashes.SHA256()),
                    salt_length=asym_padding.PSS.MAX_LENGTH
                ),
                signature,
                hashes.SHA256()
            )
        except InvalidSignature:
            raise CryptoException("Invalid signature")
        return True

    def encrypt(self, plaintext):
        iv = os.urandom(16)
        cipher = Cipher(algorithms.AES(os.urandom(32)), modes.CBC(iv), backend=default_backend())
        encryptor = cipher.encryptor()
        padder = padding.PKCS7(128).padder()
        padded_data = padder.update(plaintext) + padder.finalize()
        encrypted_data = encryptor.update(padded_data) + encryptor.finalize()
        return iv + encrypted_data

